patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCasts.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCasts.cpp
index fdef49e310f8..f1de965e7e66 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCasts.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCasts.cpp
@@ -842,6 +842,17 @@ Instruction *InstCombinerImpl::visitTrunc(TruncInst &Trunc) {
       return new ICmpInst(ICmpInst::ICMP_NE, And, Zero);
     }

+    {
+      const APInt *C;
+      // Match lshr only (ashr not needed for this pattern)
+      if (match(Src, m_LShr(m_Power2(C), m_Value(X)))) {
+        // trunc (lshr C, X) to i1 --> icmp eq X, log2(C), where C is pow2
+        // e.g., trunc (lshr 4, x) to i1 --> icmp eq x, 2
+        Constant *Log2C = ConstantInt::get(SrcTy, C->exactLogBase2());
+        return new ICmpInst(ICmpInst::ICMP_EQ, X, Log2C);
+      }
+    }
+
     {
       const APInt *C;
       if (match(Src, m_Shl(m_APInt(C), m_Value(X))) && (*C)[0] == 1) {

log.body:
define i1 @fold_ashr_power_of_2_minus_1(i8 %x) {
; CHECK-LABEL: define i1 @fold_ashr_power_of_2_minus_1(
; CHECK-SAME: i8 [[X:%.*]]) {
; CHECK-NEXT:    [[TRUNC:%.*]] = icmp ult i8 [[X]], 4
; CHECK-NEXT:    ret i1 [[TRUNC]]
  %ashr = ashr i8 15, %x
  %trunc = trunc i8 %ashr to i1
  ret i1 %trunc
}

